/**
 * EnableMFAUseCase - Unit Tests
 *
 * Tests all scenarios for enabling MFA including:
 * - Happy path (TOTP setup)
 * - Validation
 * - Already enabled check
 * - Error handling
 *
 * @author Hospital Management Team
 * @version 2.0.0
 */

import { EnableMFAUseCase, EnableMFARequest } from '../../../../src/application/use-cases/EnableMFAUseCase';
import { IUserRepository } from '../../../../src/application/repositories/IUserRepository';
import { IMFAService } from '../../../../src/application/services/IMFAService';
import { createMockUser } from '../../../helpers/user-test-helper';

describe('EnableMFAUseCase', () => {
  let useCase: EnableMFAUseCase;
  let mockUserRepository: jest.Mocked<IUserRepository>;
  let mockMFAService: jest.Mocked<IMFAService>;
  let mockLogger: any;

  beforeEach(() => {
    // Reset mocks FIRST
    jest.clearAllMocks();

    mockUserRepository = {
      findByEmail: jest.fn(),
      findById: jest.fn(),
      save: jest.fn(),
      update: jest.fn(),
      delete: jest.fn(),
      findAll: jest.fn()
    } as any;

    mockMFAService = {
      enableMFA: jest.fn(),
      disableMFA: jest.fn(),
      verifyCode: jest.fn(),
      generateBackupCodes: jest.fn(),
      validateBackupCode: jest.fn(),
      isMFAEnabled: jest.fn(),
      getMFASettings: jest.fn(),
      updateMFASettings: jest.fn(),
      checkRateLimit: jest.fn(),
      recordFailedAttempt: jest.fn(),
      clearFailedAttempts: jest.fn()
    } as any;

    mockLogger = {
      info: jest.fn(),
      warn: jest.fn(),
      error: jest.fn(),
      debug: jest.fn()
    };

    useCase = new EnableMFAUseCase(
      mockUserRepository,
      mockMFAService,
      mockLogger
    );
  });

  describe('Happy Path - 2FA App', () => {
    it('should enable MFA with 2FA app method', async () => {
      // Arrange
      const mockUser = createMockUser({
        userId: 'user-123',
        email: 'test@hospital.vn',
        fullName: 'Test User',
        roleType: 'DOCTOR',
        isActive: true,
        isEmailVerified: true
      });

      mockUserRepository.findById.mockResolvedValue(mockUser);
      mockMFAService.isMFAEnabled.mockResolvedValue(false);
      mockMFAService.enableMFA.mockResolvedValue({
        secret: 'JBSWY3DPEHPK3PXPJBSWY3DPEHPK3PXP',
        qrCodeUrl: 'otpauth://totp/Hospital%20Management:test%40hospital.vn?secret=JBSWY3DPEHPK3PXPJBSWY3DPEHPK3PXP&issuer=Hospital%20Management',
        backupCodes: ['CODE1', 'CODE2', 'CODE3']
      });

      const request: EnableMFARequest = {
        userId: 'user-123',
        method: '2fa_app'
      };

      // Act
      const result = await useCase.execute(request);

      // Assert
      expect(result.success).toBe(true);
      expect(result.secret).toBeDefined();
      expect(result.secret).toHaveLength(32);
      expect(result.qrCodeUrl).toBeDefined();
      expect(result.qrCodeUrl).toContain('otpauth://totp/');
      expect(result.backupCodes).toBeDefined();
      expect(result.backupCodes).toHaveLength(3);
      expect(result.message).toContain('Thiết lập MFA thành công');
      expect(mockMFAService.isMFAEnabled).toHaveBeenCalledWith('user-123');
      expect(mockMFAService.enableMFA).toHaveBeenCalledWith('user-123', '2fa_app', undefined, undefined);
    });

    it('should generate valid QR code URL', async () => {
      // Arrange
      const mockUser = createMockUser({
        userId: 'user-123',
        email: 'test@hospital.vn',
        fullName: 'Test User',
        roleType: 'DOCTOR',
        isActive: true,
        isEmailVerified: true
      });

      mockUserRepository.findById.mockResolvedValue(mockUser);
      mockMFAService.isMFAEnabled.mockResolvedValue(false);
      mockMFAService.enableMFA.mockResolvedValue({
        secret: 'JBSWY3DPEHPK3PXP',
        qrCodeUrl: 'otpauth://totp/Hospital%20Management:test%40hospital.vn?secret=JBSWY3DPEHPK3PXP&issuer=Hospital%20Management',
        backupCodes: ['CODE1']
      });

      const request: EnableMFARequest = {
        userId: 'user-123',
        method: '2fa_app'
      };

      // Act
      const result = await useCase.execute(request);

      // Assert
      // URL label 1�n ma b0n, nan email 1 ta 1n dang test%40hospital.vn
      expect(result.qrCodeUrl).toContain('test%40hospital.vn');
      // Encoded issuer and label should contain encoded space (+ in query, %20 in label)
      expect(result.qrCodeUrl).toContain('Hospital%20Management');
      expect(result.qrCodeUrl).toContain('secret=');
      expect(result.qrCodeUrl).toContain('issuer=');
    });
  });

  describe('Validation', () => {
    it('should reject missing userId', async () => {
      // Arrange
      const request: EnableMFARequest = {
        userId: '',
        method: '2fa_app'
      };

      // Act
      const result = await useCase.execute(request);

      // Assert
      expect(result.success).toBe(false);
      expect(result.error).toBe('VALIDATION_ERROR');
      expect(result.message).toContain('User ID là bắt buộc');
    });

    it('should reject invalid method', async () => {
      // Arrange
      const request: EnableMFARequest = {
        userId: 'user-123',
        method: 'invalid' as any
      };

      // Act
      const result = await useCase.execute(request);

      // Assert
      expect(result.success).toBe(false);
      expect(result.message).toContain('Phương thức MFA không hợp lệ');
    });

    it('should require phone number for SMS method', async () => {
      // Arrange
      const request: EnableMFARequest = {
        userId: 'user-123',
        method: 'sms'
      };

      // Act
      const result = await useCase.execute(request);

      // Assert
      expect(result.success).toBe(false);
      expect(result.message).toContain('Số điện thoại là bắt buộc');
    });

    it('should require email for email method', async () => {
      // Arrange
      const request: EnableMFARequest = {
        userId: 'user-123',
        method: 'email'
      };

      // Act
      const result = await useCase.execute(request);

      // Assert
      expect(result.success).toBe(false);
      expect(result.message).toContain('Email là bắt buộc');
    });
  });

  describe('User Not Found', () => {
    it('should return error when user does not exist', async () => {
      // Arrange
      mockUserRepository.findById.mockResolvedValue(null);

      const request: EnableMFARequest = {
        userId: 'non-existent-user',
        method: '2fa_app'
      };

      // Act
      const result = await useCase.execute(request);

      // Assert
      expect(result.success).toBe(false);
      expect(result.error).toBe('USER_NOT_FOUND');
      expect(result.message).toContain('Người dùng không tồn tại');
    });
  });

  describe('MFA Already Enabled', () => {
    it('should reject if MFA is already enabled', async () => {
      // Arrange
      const mockUser = createMockUser({
        userId: 'user-123',
        email: 'test@hospital.vn',
        fullName: 'Test User',
        roleType: 'DOCTOR',
        isActive: true,
        isEmailVerified: true
      });

      mockUserRepository.findById.mockResolvedValue(mockUser);
      mockMFAService.isMFAEnabled.mockResolvedValue(true);

      const request: EnableMFARequest = {
        userId: 'user-123',
        method: '2fa_app'
      };

      // Act
      const result = await useCase.execute(request);

      // Assert
      expect(result.success).toBe(false);
      expect(result.error).toBe('MFA_ALREADY_ENABLED');
      expect(result.message).toContain('MFA đã được kích hoạt');
    });
  });

  describe('Backup Codes', () => {
    it('should generate backup codes', async () => {
      // Arrange
      const mockUser = createMockUser({
        userId: 'user-123',
        email: 'test@hospital.vn',
        fullName: 'Test User',
        roleType: 'DOCTOR',
        isActive: true,
        isEmailVerified: true
      });

      mockUserRepository.findById.mockResolvedValue(mockUser);
      mockMFAService.isMFAEnabled.mockResolvedValue(false);
      mockMFAService.enableMFA.mockResolvedValue({
        secret: 'JBSWY3DPEHPK3PXP',
        qrCodeUrl: 'otpauth://totp/...',
        backupCodes: ['CODE1', 'CODE2', 'CODE3', 'CODE4', 'CODE5']
      });

      const request: EnableMFARequest = {
        userId: 'user-123',
        method: '2fa_app'
      };

      // Act
      const result = await useCase.execute(request);

      // Assert
      expect(result.backupCodes).toBeDefined();
      expect(result.backupCodes?.length).toBeGreaterThan(0);
    });

  });

  describe('Error Handling', () => {
    it('should handle database errors gracefully', async () => {
      // Arrange
      const mockUser = createMockUser({
        userId: 'user-123',
        email: 'test@hospital.vn',
        fullName: 'Test User',
        roleType: 'DOCTOR',
        isActive: true,
        isEmailVerified: true
      });

      mockUserRepository.findById.mockResolvedValue(mockUser);
      mockMFAService.isMFAEnabled.mockResolvedValue(false);
      mockMFAService.enableMFA.mockRejectedValue(new Error('Database error'));

      const request: EnableMFARequest = {
        userId: 'user-123',
        method: '2fa_app'
      };

      // Act
      const result = await useCase.execute(request);

      // Assert
      expect(result.success).toBe(false);
      expect(result.error).toBe('MFA_SETUP_FAILED');
      expect(mockLogger.error).toHaveBeenCalled();
    });
  });
});

